#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
int n,a[N],dp[N];
int main(){
    while(cin>>a[++n]);
    n--;
    int len=0;
    dp[0]=1e5;
    for(int i=1;i<=n;i++){
        if(a[i]<=dp[len])
            dp[++len]=a[i];
        else{
            int l=1,r=len;
            while(l<r){
                int mid=(l+r)/2;
                if(dp[mid]<a[i])
                    r=mid;
                else
                    l=mid+1;
            }
            dp[l]=max(dp[l],a[i]);
        }
    }
    printf("%d\n",len);
    len=0;
    dp[0]=0;
    for(int i=1;i<=n;i++){
        if(a[i]>dp[len])
            dp[++len]=a[i];
        else{
            int l=1,r=len;
            while(l<r){
                int mid=(l+r)/2;
                if(dp[mid]>=a[i])
                    r=mid;
                else
                    l=mid+1;
            }
            dp[l]=min(dp[l],a[i]);
        }
    }
    printf("%d\n",len);
    return 0;
}
